VALUES
  ('social-worker-moex-01441', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關科學管理學派的相關敘述，下列何者錯誤？', '["泰勒（F.W.Taylor）是科學管理學派的創始者，被視為是科學管理之父", "假設工人偏好簡易的工作，且工作時強調自我負責", "主張直接觀察工人的問題與工作態度，以探究如何提高生產效率與品質", "發現工人工作動機真正想獲取的是經濟安全"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01442', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關人群關係學派的敘述，下列何者錯誤？', '["假設人如果工作有效率，便會快樂", "最具代表性的人物是芙麗特（MaryParkerFollett）、梅耶（E.Mayo）", "霍桑研究中發現社會和人際因素要比物理環境對生產力的影響大", "梅耶歸納出行為和感情是緊密關聯的，團體對個人的行為深具影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01443', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織學習（organizationallearning）是管理新思維，下列敘述何者錯誤？', '["知識管理與學習型組織均屬於組織學習觀點的一環", "組織學習積極性的意涵是要導正其想法或行動上的錯誤", "學習型組織的核心概念即是「解決問題」", "知識管理是網路新經濟時代新興的管理思潮與方法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01444', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關新管理主義對社會工作的意涵，下列何者錯誤？', '["管理知識是主流，而非專業知識", "照顧和關懷為關係的基礎，而非現金和契約", "效率是判準，而非效能", "品質等同於標準化與文件化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01445', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '甲機構為能掌握脆弱家庭的福利需求，以能規劃適當的服務方案，因此邀集服務區域內50位脆 弱家庭的成員，辦理5場焦點團體，收集相關意見。依據Bradshaw所提出的需求觀點，甲機構 的評量是基於下列那種需求？', '["感受性需求", "規範性需求", "表達性需求", "比較性需求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01446', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某方案的目標（objectivity）陳述為「本方案為期 3 年，在第 1 年的服務結束後，參與本方案之 20名受暴婦女，至少有40%者能順利就業3個月以上。」若以效能（effectiveness）導向的方案 目標撰寫構成要素來檢視，「至少有40%者能順利就業3個月以上」係指下列那一個要素？', '["活動設計", "改變之標的", "執行與測量目標達成之責任歸屬", "欲達成的結果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01447', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理有很多功能及程序，下列何者為管理程序的最後一個環節？', '["規劃", "組織", "控制", "決策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01448', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '為能確認方案執行的狀況與進行方案評量，相關方案資料的蒐集有其重要性。對於方案資料類型 的說明，下列何者正確？', '["「涵蓋範圍資料」可以回答「方案滿足社區需求的程度為何？」", "「公平性資料」可以回答「方案依設計而執行的程度為何？」", "「過程資料」可以回答「方案所服務的次地區及次族群的程度為何？」", "「成本效益資料」可以回答「方案達成可測量效應之程度為何？」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01449', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「在乎方案的結果而不在乎它內部的操作過程」，此為下列那種評估模式的概念？', '["目標檢核評估（objectives-basedevaluation）", "黑箱評估（blackboxevaluation）", "責信模式（accountabilitymodel）", "專家意見模式（expertopinionmodel）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01450', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關「效力評估」（effortevaluation）的敘述，下列何者錯誤？', '["屬於「形成性評估」的一種", "偏重在評估方案能為服務對象帶來那些改變", "用以評估的資料可同時包含量化與質化資料", "評估的目的在於對方案的控管，因此常被視為是監督方案執行的工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
